UPDATE events SET description = '<p>Please note that the CARE Showcase includes two programs, starting at 5:00 and 7:30 PM, presenting different work — stay tuned for an update on the run of show for each screening soon!</p>
<p><a href="https://www.blockmuseum.northwestern.edu/cinema/2026/china-america-reel-ecology-care-student-film-showcase.html" target="_blank" rel="noopener">RSVP Screening 1 &#8211; 5:00 PM</a></p>
