UPDATE events SET description = '<p>The CAA Services to Artists Committee(SAC) is excited to invite you to Parallel Worlds, an exhibition imagining parallel worlds, temporal shifts, and alternative futures.<br>
Join us for a CAA-organized special offsite exhibition presented by SAC at Heritage Auctions&#8217; gallery. A free shuttle bus to the exhibition will be available Thursday, 4:30-8:30 p.m.</p>
<p>RSVP or ID required to enter. Reception will be held Thursday, 6:30-8:30 p.m<br>
RSVP her: <a href="https://forms.office.com/pages/responsepage.aspx?id=JIXjW12zr0-lcPgY7h7QkS6aU1K_pWBOt0rKpq1t66ZUOFhKRElGNlIxTlVFUVZFQ0xSMFFYTkUxRi4u&amp;route=shorturl" target="_blank" rel="noopener">https://forms.office.com/pages/responsepage.aspx?id=JIXjW12zr0-lcPgY7h7QkS6aU1K_pWBOt0rKpq1t66ZUOFhKRElGNlIxTlVFUVZFQ0xSMFFYTkUxRi4u&amp;route=shorturl</a></p>
